using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Traverse tree and print types we find
void PrintTree(BaseNode node, int depth = 0)
{
    var indent = new string(' ', depth * 2);
    var typeName = node.GetType().Name;

    // Focus on interesting nodes
    if (node is Error err)
    {
        Console.WriteLine($"{indent}[ERROR] {err.Code}: {err.Text}");
        Console.WriteLine($"{indent}  File: {err.File}:{err.LineNumber}:{err.ColumnNumber}");
    }
    else if (node is Message msg && msg.Text?.Contains("error") == true)
    {
        Console.WriteLine($"{indent}[MSG] {msg.Text?.Substring(0, Math.Min(200, msg.Text.Length))}");
    }
    else if (typeName == "SourceFile")
    {
        Console.WriteLine($"{indent}[SourceFile] {(node as NamedNode)?.Name}");
    }

    if (node is TreeNode treeNode)
    {
        foreach (var child in treeNode.Children)
        {
            if (child is BaseNode childNode)
                PrintTree(childNode, depth + 1);
        }
    }
}

// Find which projects failed vs succeeded by checking if they have errors
Console.WriteLine("=== ANALYSIS ===\n");

// The key question: did Api fail due to its own errors or cascading from Services?
var topProjects = build.FindChildrenRecursive<Microsoft.Build.Logging.StructuredLogger.Project>();
var seen = new HashSet<string>();
foreach (var proj in topProjects)
{
    var errors = proj.FindChildrenRecursive<Error>();
    var key = $"{proj.Name}:{errors.Count}";
    if (seen.Add(key))
    {
        Console.WriteLine($"Project: {proj.Name}, Errors in this project: {errors.Count}");
        foreach (var e in errors)
        {
            Console.WriteLine($"  -> {e.Code}: {e.Text}");
        }
    }
}

// Now extract the embedded source archive using reflection
Console.WriteLine("\n=== EMBEDDED FILES ===");
var allNodes = build.FindChildrenRecursive<NamedNode>();
foreach (var n in allNodes)
{
    var typeName = n.GetType().Name;
    if (typeName.Contains("Source") || typeName.Contains("Archive") || typeName.Contains("Embed"))
    {
        Console.WriteLine($"  Type: {typeName}, Name: {n.Name}");
    }
}

// Try to read embedded files through the binary log reader directly
Console.WriteLine("\n=== READING EMBEDDED FILES DIRECTLY ===");
var reader = new BinLogReader();
var sourceFiles = reader.ReadSourceFiles(binlogPath);
foreach (var (path, content) in sourceFiles)
{
    if (!path.Contains("/usr/share/dotnet/") && !path.Contains("/root/"))
    {
        Console.WriteLine($"\n--- {path} ---");
        Console.WriteLine(content);
    }
}
